const fs = require('fs');
const path = require('path');
const _ = require('lodash');

const Config = require('./config');

/**
 *
 */
class Env extends Config{

    constructor(){

        super();

        const envFileNames = _getEnvFileNames.call(this);

        this.sourceFileName = envFileNames.source;
        this.targetFileName = envFileNames.target;
    }
}

/**
 *
 * @returns {{}}
 * @private
 */
function _getEnvFileNames(){

    let ret = {};

    const environment = this.app.environment;

    ret.source = 'env.js';
    ret.target = environment;

    return ret;
}

module.exports = Env;